head.script:
// id       : op_303_03_33b
// 이름     : CY STOCK 현황
// 경로     : 물류/실적현황/컨테이너 재고/
// 작 성 자 :
// 작 업 일 :
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================
scwin.params = "";
scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");     // 서버를 기준으로 현재 날짜 반환
scwin.memJson = $c.data.getMemInfo();                       //사용자 정보

scwin.loUpperLobranCd = scwin.memJson.loUpperLobranCd;      // 점소
scwin.userClsCd = scwin.memJson.userClsCd;
//사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))

scwin.loginClntNo = scwin.memJson.clntNo;                   // 거래처번호
scwin.loginClntNm = scwin.memJson.clntNm;                   // 거래처명
scwin.lobranCd = scwin.memJson.lobranCd;                    // 점소명
scwin.chk_shpCo = "";
scwin.chk_cy = "";

if(scwin.loUpperLobranCd == null ) scwin.loUpperLobranCd = "";
if(scwin.userClsCd == null) scwin.userClsCd = "";
if(scwin.loginClntNo == null) scwin.loginClntNo = "";
if(scwin.loginClntNm == null) scwin.loginClntNm = "";
if(scwin.lobranCd == null) scwin.lobranCd = "";

scwin.params = $c.data.getParameter();                                          // 파라미터를 읽어 온다.
scwin.reqLobranCd = scwin.params.lobranCd == null? "" : scwin.params.lobranCd;  // 점소코드 
scwin.reqCy = scwin.params.cy == null? "" : scwin.params.cy;                    // CY코드 
scwin.reqCyNm = scwin.params.cyNm == null? "" : scwin.params.cyNm;              // Cy명 


scwin.onpageload = function() {
    $c.sbm.execute(sbm_lobran);
};

scwin.onUdcCompleted = function() {

    if(scwin.userClsCd != "01"){                    // 사용자가 그룹사가 아닐때
        ed_shpCo.setValue(scwin.loginClntNo);       // 거래처번호
        scwin.chk_shpCo = scwin.loginClntNo;
        ed_shpCoNm.setValue(scwin.loginClntNm);     // 거래처명
        udc_shpCo.setReadOnly(true);                // 거래처 입력 금지
        $c.gus.cfDisableObjects([btn_shpCo]);
        tbx_td_con_bran.setValue("");               // 점소
        acb_con_bran.hide();                        // 점소

        scwin.f_setLine();                          // 라인콤보
        acb_lineCd.focus();                         // LINE
    } else {
        scwin.f_setLine();                          // 라인콤보
        ed_shpCo.focus();                           // 거래처번호
        acb_con_bran.setValue(scwin.lobranCd);      // 점소
    }
}
scwin.co_ds_LoBran_ondataload = function () {
    acb_con_bran.setSelectedIndex(0);
    acb_con_bran.setValue(scwin.loUpperLobranCd);
}

scwin.sbm_lobran_submitdone = async function (e) {
    // 점소가 NULL이 아닐경우 넘어온 점소로 세팅함.
    if ( scwin.reqLobranCd != "" ) {
        for (var i=0; i<co_ds_LoBran.getRowCount(); i++) {
            if ( co_ds_LoBran.getCellData(i,"lobranCd") == scwin.reqLobranCd ) {
                //lc_con_bran.Index = (i-1);
                acb_con_bran.setValue(scwin.reqLobranCd);
                break;
            }
        }
    }

    if (scwin.reqCy != "" ) {
        ed_con_cy.setValue(scwin.reqCy);
        scwin.chk_cy = scwin.reqCy;
    }
    if (scwin.reqCyNm != "" ) {
        ed_con_cyNm.setValue(scwin.reqCyNm);
    }

    ed_stDt.setValue($c.date.addMonth(scwin.vCurDate, -1));
    ed_endDt.setValue(scwin.vCurDate);

    await scwin.f_DateSet();

    // 연결화면에서 OPEN시는 로딩시 자동 조회 하도록 한다.
    if (scwin.reqCy != "" ) {
        scwin.f_Retrieve();
    }
};

scwin.sbm_lobran_submiterror = function (e) {

};

//-------------------------------------------------------------------------
// 라인콤보 조회 
//-------------------------------------------------------------------------
scwin.f_setLine = function(){
    var jsonData = {
        sysCd  : "LineEBC"
        ,queryId : "retrieveLineEachShpCoCdCombo"
        ,param1 : scwin.loginClntNo
        ,param2 : scwin.userClsCd
        ,param3 : ed_shpCo.getValue()
    }

    ds_srchLine.setJSON(jsonData);
    $c.sbm.execute(sbm_line);
}

scwin.sbm_line_submitdone = function (e) {
    acb_lineCd.setSelectedIndex(0);
};

scwin.sbm_line_submiterror = function (e) {

};

//-------------------------------------------------------------------------
// 날자 및 조회조건 셋팅
//-------------------------------------------------------------------------
scwin.f_DateSet = function(){
	var viewDt = 0;
    for(var i=1;i<=31;i++){
        if(i==1){
            viewDt = ed_stDt.getValue();
        }else{
            viewDt = $c.date.addDate(viewDt, 1);
        }

        //stDt1
        gr_retrieveLine.setHeaderValue("stDt"+i, $c.date.formatDateTime(viewDt, "yyyy/MM/dd"));
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {

    if (! await $c.gus.cfIsAfterDate(ed_stDt.getValue(), ed_endDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_endDt.focus();
        return;
    }

    if (ed_stDt.getValue() == "" || ed_stDt.getValue().length != 8) {
        await $c.gus.cfAlertMsg("시작일자가 잘못되었습니다.");
        return;
    }
    if (ed_endDt.getValue() == "" || ed_endDt.getValue().length != 8) {
        await $c.gus.cfAlertMsg("종료일자가 잘못되었습니다.");
        return;
    }

    ds_oGDS_view_cond.set("bran" , acb_con_bran.getValue());
    ds_oGDS_view_cond.set("cy"   , ed_con_cy.getValue());
    ds_oGDS_view_cond.set("line" , acb_lineCd.getValue());
    ds_oGDS_view_cond.set("shpCo", ed_shpCo.getValue());
    ds_oGDS_view_cond.set("typ"  , acb_typ.getValue());

    ds_oGDS_view_cond.set("stDt" , ed_stDt.getValue());
    ds_oGDS_view_cond.set("endDt", ed_endDt.getValue());

    $c.sbm.execute(sbm_retrieve);
};


scwin.sbm_retrieve_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var rowcnt = ds_retrieveLine.getRowCount();
    tbx_totalRows.setValue(rowcnt);

	if (rowcnt == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
	}
    gr_retrieveLine.setFocusedCell(0, "clntNm", false);
    scwin.f_DateSet();
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfShowError(e);
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function(){
    if(scwin.userClsCd != "01"){  //사용자가 그룹사가 아닐때
        ed_shpCo.setValue(scwin.loginClntNo);
        scwin.chk_shpCo = scwin.loginClntNo;
        ed_shpCoNm.setValue(scwin.loginClntNm);
        $c.gus.cfInitObjects([ed_con_cy,ed_con_cyNm,acb_lineCd]);
        acb_lineCd.focus();
    } else {
        acb_con_bran.setSelectedIndex(0);
        $c.gus.cfInitObjects([ed_con_cy,ed_con_cyNm,acb_lineCd,ed_shpCo,ed_shpCoNm]);
        ed_shpCo.focus();
    }

    ed_stDt.setValue($c.date.addMonth(scwin.vCurDate, -1));
    ed_endDt.setValue(scwin.vCurDate);
};

//-------------------------------------------------------------------------
// TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpText = function(inObj, codeObj, disGubun) {

    var pCode = "";
    var pName = "";

    if (inObj.getValue().trim() == "") {
        codeObj.setValue("");
        if (disGubun == 3) {
            scwin.f_setLine();
        }
        return;
    }

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if(inObj.getReadOnly() || (inObj.getValue() == inObj.hidVal))
    return;

    if (codeObj != null){    
        if (codeObj.tagName == "OBJECT") {
            codeObj.setValue("");
            //codeObj.value = "";
        } else {
            codeObj.setValue("");
            //codeObj.value = "";
            codeObj.hidVal = "";
        }
    }
    pName =  inObj.getValue();
    scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면

    switch (disGubun)
    {
        case 1:
            // CY 팝업
            //rtnList = cfCommonPopUp('retrieveWrkPlInfo' // XML상의 SELECT ID    
            rtnList = udc_con_cy.cfCommonPopUp(scwin.udc_con_cyCalllback // XML상의 SELECT ID    
                                    ,pCode                  // 화면에서의  Code Element의   Value
                                    ,pName                  // 화면에서의  Name Element의   Value
                                    ,pClose                 // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                    ,null                   // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null                   // Title순서    
                                    ,null                   // 보여주는 각 컬럼들의 폭  
                                    ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                    ,',' + acb_con_bran.getValue()// SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null                   // POP-UP뛰을때 원도우의    사용자 정의 폭
                                    ,null                   // POP-UP뛰을때 우도우의    사용자 정의 높이    
                                    ,null                   // 윈도우 위치 Y좌표    
                                    ,null                   // 윈도우 위치 X좌표
                                    ,null                   // 중복체크여부 ("F")
                                    ,pAllSearch                 // 전체검색허용여부 ("F")
                                    ,"CY,CY코드,CY명"               // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ); 

            //cfSetReturnValue(rtnList, ed_con_cy, ed_con_cyNm);
            break;

        case 2:
            break;

        case 3:
            // 선사 팝업
            //rtnList = cfCommonPopUp('retrieveClntInfo'      // XML상의 SELECT ID    
            rtnList = udc_shpCo.cfCommonPopUp(scwin.udc_shpCoCallback      // XML상의 SELECT ID    
                                    ,pCode                  // 화면에서의 ??? Code Element의    Value
                                    ,pName                  // 화면에서의 ??? Name Element의    Value
                                    ,pClose                 // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                    ,null                   // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null                   // Title순서    
                                    ,null                   // 보여주는 각 컬럼들의 폭  
                                    ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                    ,'SHP'                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null                   // POP-UP뛰을때 원도우의    사용자 정의 폭
                                    ,null                   // POP-UP뛰을때 우도우의    사용자 정의 높이    
                                    ,null                   // 윈도우 위치 Y좌표    
                                    ,null                   // 윈도우 위치 X좌표
                                    ,null                   // 중복체크여부 ("F")
                                    ,pAllSearch                 // 전체검색허용여부 ("F")
                                    ,"선사,선사코드,선사명"             // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    ); 

            //cfSetReturnValue(rtnList, ed_shpCo, ed_shpCoNm);
            //f_setLine();
        break;  

        default:
            break;
    }
};


//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel = async function() {
    var rowCount = ds_retrieveLine.getRowCount();
    if ( rowCount == 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
          return false;
    }
    let rtn = await $c.win.confirm( "Excel로 다운로드 하시겠습니까?" ); 
    if ( rtn ) {
        let sheetTitle = "CY STOCK 현황";	
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xls", 
            sheetName: sheetTitle
        };

        $c.data.downloadGridViewExcel(gr_retrieveLine, options, infoArr);
    }
}


//-------------------------------------------------------------------------
// 조회 조건 초기화 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

//-------------------------------------------------------------------------
// 조회 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.udc_shpCo_onblurCodeEvent = function (e) {

    if (ed_shpCo.getValue().trim() == "") {
        ed_shpCoNm.setValue("");
        scwin.f_setLine();
        return;
    }

    scwin.f_openCommonPopUp(3, ed_shpCo.getValue(), ed_shpCoNm.getValue(), 'T', 'T');
};

scwin.udc_shpCo_onblurNameEvent = function (e) {
    if (ed_shpCoNm.getValue().trim() == "") {
        ed_shpCo.setValue("");
        scwin.f_setLine();
        return;
    }
    scwin.f_openCommonPopUp(3, ed_shpCo.getValue(), ed_shpCoNm.getValue(), 'T', 'T');
};

scwin.udc_shpCo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_shpCo.getValue(), ed_shpCoNm.getValue(), 'T', 'T');
};

scwin.udc_shpCo_onviewchangeNameEvent = function (info) {
    let newValue = info.newValue;
    if(newValue == ""){
        ed_shpCo.setValue("");
        scwin.f_setLine();
        return;
    }
    scwin.f_openCommonPopUp(3, ed_shpCo.getValue(), ed_shpCoNm.getValue(), 'T', 'T');
};

scwin.udc_con_cy_onblurCodeEvent = function (e) {
    if(ed_con_cy.getValue() != ""){
        ed_con_cyNm.setValue("");
    }
    scwin.f_openCommonPopUp(1, ed_con_cy.getValue(), ed_con_cyNm.getValue(), 'T', 'T');
};

scwin.udc_con_cy_onblurNameEvent = function (e) {
    if(ed_con_cyNm.getValue() != ""){
        ed_con_cy.setValue("");
    }
    scwin.f_openCommonPopUp(1, ed_con_cy.getValue(), ed_con_cyNm.getValue(), 'T', 'T');
};

scwin.udc_con_cy_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_con_cy.getValue(), ed_con_cyNm.getValue(), 'T', 'T');
};

scwin.udc_con_cy_onviewchangeNameEvent = function (info) {
    let newValue = info.newValue;
    if(newValue == ""){
        ed_con_cy.setValue("");
        return;
    }
    scwin.f_openCommonPopUp(1, ed_con_cy.getValue(), ed_con_cyNm.getValue(), 'T', 'T');
};

scwin.udc_con_cyCalllback = function(rtnList){
    $c.gus.cfSetReturnValue(rtnList, ed_con_cy, ed_con_cyNm);
};

scwin.udc_shpCoCallback = function(rtnList){
    $c.gus.cfSetReturnValue(rtnList, ed_shpCo, ed_shpCoNm);
    scwin.f_setLine();
};

scwin.gr_retrieveLine_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    var rowCnt = ds_retrieveLine.getRowCount();
    var row = rowIndex;
    if(rowCnt>0){
    //f (ds_retrieveLine.RowLevel(row) == 0) {
        /*2006.07.26 선사 정보가 없어도 CY별 재고현황이 OPEN되도록 요청함.
        if (ds_retrieveLine.NameValue(Row, "shpCo") == "" || ds_retrieveLine.NameValue(row, "shpCo") == "") {
                alert("선사 관련정보가 없습니다.");
        } else 
        */
        if (ds_retrieveLine.getCellData(row, "line") == "" || ds_retrieveLine.getCellData(row, "lineNm") == "") {
            $.c.win.alert("LINE 관련정보가 없습니다.");
        } else if (ds_retrieveLine.getCellData(row, "cy") == "" || ds_retrieveLine.getCellData(row, "cyNm") == "") {
            $.c.win.alert("CY 관련정보가 없습니다.");
            return;
        } else {
            var argParam = "";
            argParam += ds_retrieveLine.getCellData(row, "shpCo") + "^";
            argParam += ds_retrieveLine.getCellData(row, "shpCoNm") + "^";
            argParam += ds_retrieveLine.getCellData(row, "line") + "^";
            argParam += ds_retrieveLine.getCellData(row, "cy") + "^";
            argParam += ds_retrieveLine.getCellData(row, "cyNm")+ "^";
            argParam += ds_retrieveLine.getCellData(row, "cntrTypCd") + "^"
            argParam += "R";
            //cfTabMenuUpdate("/ds/op/wrkrslts/stockrslts/op_303_03_03b.jsp?argParams=" + argParam, "CY별 재고현황");

            //let condition = "?";

            let pgmId = "op_303_03_03b.xml";
            let strCertiNoDetailUrl = "/ui/ds/op/wrkrslts/stockrslts/" + pgmId;
            let title = "CY별 재고현황"

            let paramObj = {
                'argParams' : argParam
            }

            //$c.gus.cfTabMenuUpdate(strCertiNoDetailUrl+condition, title);
            $c.win.openMenu(title, strCertiNoDetailUrl, pgmId, paramObj);
        }
    //}
    }
};
